"""Router for User — generated by BackendAgent."""
from __future__ import annotations

from fastapi import APIRouter, HTTPException

from schemas import UserCreate, UserUpdate, UserResponse
from services import UserService

router = APIRouter()
_service = UserService()


@router.get("/", response_model=list[UserResponse])
def list_users() -> list:
    """List all users."""
    return _service.list_users()


@router.post("/", response_model=UserResponse, status_code=201)
def create_user(data: UserCreate) -> object:
    """Create a new user."""
    try:
        return _service.create_user(data.model_dump())
    except NotImplementedError:
        raise HTTPException(status_code=501, detail="Not yet implemented")


@router.get("/{id}", response_model=UserResponse)
def get_user(id: str) -> object:
    """Get a single user by id."""
    item = _service.get_user(id)
    if item is None:
        raise HTTPException(status_code=404, detail="User not found")
    return item


@router.put("/{id}", response_model=UserResponse)
def update_user(id: str, data: UserUpdate) -> object:
    """Update an existing user."""
    try:
        result = _service.update_user(id, data.model_dump(exclude_unset=True))
    except NotImplementedError:
        raise HTTPException(status_code=501, detail="Not yet implemented")
    if result is None:
        raise HTTPException(status_code=404, detail="User not found")
    return result


@router.delete("/{id}", status_code=204)
def delete_user(id: str) -> None:
    """Delete a user. Level-3 action — requires permission check."""
    if not _service.delete_user(id):
        raise HTTPException(status_code=404, detail="User not found")
